local xml2lua = require "xml2lua"
local xmlhandler = require "xmlhandler"

local function parse_soap_request()
    local request_body = ngx.req.get_body_data()
    if not request_body then
        ngx.status = 400
        ngx.say("Missing request body")
        ngx.exit(400)
        return
    end
    
    local parser = xml2lua.parser()
    parser:parse(request_body)
    
    local handler = xmlhandler.tree.new()
    parser:parse(request_body, handler)
    
    return handler.root
end

local function extract_soap_data(xml_root)
    local data = {}
    
    if xml_root and xml_root.name == "Envelope" then
        local body = xml_root[1]
        if body and body.name == "Body" then
            local operation = body[1]
            if operation then
                data.operation = operation.name
                data.params = {}
                
                for i, child in ipairs(operation) do
                    data.params[child.name] = child.text
                end
            end
        end
    end
    
    return data
end

local function process_soap_request()
    local xml_root = parse_soap_request()
    local soap_data = extract_soap_data(xml_root)
    
    return soap_data
end

local soap_data = process_soap_request()
